"""
MKT Christ Commentary — Matthew chapters 1–4
Run: python3 scripts/zc-christ-matthew-1-4.py

Source data used:
- data/interlinear/matthew.json
- data/translation/glossary-greek.json (Christos, basileia, euangelion)
- data/translation/draft/mediating/matthew.json (MKT text)
- data/echoes/matthew.json (fulfillment echoes established for ch 1–4)
- data/commentary/mkt-context/matthew.json (community setting, terminology)

Key decisions in this range:
- "Matthew" used as the author designation, consistent with context scripts
- Directness levels stated in prose ("a direct fulfillment", "as a type", "the theme of")
- Genealogy (1:1–17): individual ancestors get brief entries noting their covenantal role;
  structural entries (v1, v17) carry the full Christological argument
- Four women in the genealogy (Tamar, Rahab, Ruth, Bathsheba): shadow of grace through
  irregular channels — anticipating the birth that will also be scandalous to onlookers
- Fulfillment quotations: Mic 5:2 and Isa 7:14 are direct; Hos 11:1 (Matt 2:15) is
  typological (Israel-as-son → Jesus-as-Son); Jer 31:15 (Matt 2:17) is pattern-fulfillment
- Temptation (4:1–11): Jesus recapitulates Israel's three great wilderness failures and
  succeeds; every response quotes Deuteronomy, the covenant-renewal book
- Baptism declaration (3:17): synthesis of Ps 2:7 (royal Messiah) + Isa 42:1 (Servant)
- Isa 9:1–2 quotation (4:15–16): direct fulfillment; Galilee ministry foreshadows the
  Gentile mission consummated at 28:19
- NOTE: this script adds ch 1–4 complete coverage to the existing JSON file; any verses
  already present (e.g., 1:1, 1:23, 2:15, 3:17, 4:4, 4:17) will not be overwritten
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html


MATTHEW = {
  "1": {
    "1": '<p>A direct fulfillment: the opening line compresses the Gospel\'s entire Christological argument. Jesus is <em>Christos</em> (the anointed king), son of David (heir of the 2 Sam 7:12–16 covenant promising an eternal throne), and son of Abraham (heir of the Gen 12:1–3 promise that all nations would be blessed through one descendant). Matthew does not begin with theology but with genealogy — the argument that Jesus stands at the end of Israel\'s entire covenantal history as its appointed resolution. The <em>biblos geneseos</em> (book of the genealogy) echoes Gen 5:1 LXX (book of the generations of Adam), framing Jesus as the new Adam, head of a new humanity.</p>',

    "2": '<p>Abraham, Isaac, and Jacob are the patriarchal bearers of the covenant promise. Each name traces the thread God explicitly passed from father to son: the promise to Abraham (Gen 12, 15, 17, 22), confirmed to Isaac (Gen 26:3–4) and Jacob (Gen 28:13–14). Judah is named with his brothers — the twelve sons, the twelve tribes — anticipating the reconstituted twelve gathered around Jesus (10:1–4). The genealogy is not biography; it is covenant-history moving toward its goal.</p>',

    "3": '<p>Tamar is the first of four women in the genealogy, each entering the messianic line through irregular or scandalous circumstances. Tamar secured her covenant rights by posing as a prostitute (Gen 38:6–30) — a shadow of the pattern through which God\'s redemptive purpose works: through the margins, through social disgrace, through what the world calls shameful. Her inclusion anticipates the birth that will also be misread by onlookers. The line of promise does not run through tidy respectability but through grace that meets people in the failures of the covenant.</p>',

    "4": '<p>Amminadab and Nahshon are from the wilderness generation (Num 1:7; 2:3); Nahshon led the tribe of Judah in the Sinai census. The genealogy passes through the entire span of Israel\'s history: patriarchs, wilderness, conquest, monarchy, exile. Christ inherits the whole story, not only its high points. His coming is not a fresh start disconnected from Israel\'s past but the promised resolution that was always embedded in it.</p>',

    "5": '<p>Rahab is the Canaanite prostitute of Jericho who harbored the spies and was brought into Israel by faith (Josh 2; 6:25; Heb 11:31); Ruth is the Moabite whose covenant loyalty (<em>hesed</em>) to Naomi brought her into Israel through Boaz. Both women are Gentiles — doubly excluded (Deut 23:3 excludes Moabites). Their presence in the Messiah\'s line is a shadow pointing forward to the Great Commission (28:19): the one born from this line will gather the nations into the covenant family. The Gentile mission is already written into the genealogy.</p>',

    "6": '<p>David the king — the pivot on which the genealogy turns. The Davidic covenant of 2 Sam 7:12–16 is Matthew\'s central OT claim: an eternal throne, a son whom God will call his own son, a kingdom without end. Bathsheba is named as "the wife of Uriah" rather than by name — the fourth irregular woman, introduced through David\'s adultery and murder (2 Sam 11). The Messiah\'s royal line passes through the greatest sin of the greatest king. This is not incidental: the grace that runs through Tamar, Rahab, and Ruth runs also through here. The line of the Redeemer carries the full weight of what it comes to redeem.</p>',

    "7": '<p>Solomon to Rehoboam marks the moment the kingdom split (1 Kgs 12). The genealogy does not skip the division or the subsequent decline; it passes through them. The Davidic promise outlasted the kingdom\'s fracture — carried not by political continuity but by God\'s unconditional commitment (2 Sam 7:15, "my steadfast love will not depart from him"). Christ inherits a dynasty that has been without a throne for six centuries. The royal promise endured because it was God\'s promise, not Israel\'s achievement.</p>',

    "8": '<p>Asa was a reformer; Jehoshaphat maintained covenant faithfulness; Joram introduced Baal worship through his marriage to Athaliah (2 Kgs 8:18). The genealogy does not select only faithful kings. The covenant is unconditional (2 Sam 7:15); it carries through apostasy and reform alike. This is the structure of the Christ-story itself: the one who comes does not arrive because his ancestors earned it but because the Father\'s promise will not fail.</p>',

    "9": '<p>Three more kings — Jotham (faithful), Ahaz (apostate), Hezekiah (reformer). Ahaz is notable: the sign of Immanuel (v23) was given to him specifically, a king who refused to ask God for a sign (Isa 7:10–12). The incarnation does not wait for a worthy generation; it comes into the specific historical situation of Israel\'s failure and incomprehension, promised to a king whose unbelief made the sign necessary.</p>',

    "10": '<p>Hezekiah to Manasseh — the sharpest contrast in the Judean monarchy. Manasseh\'s fifty-five years of idolatry and child sacrifice are cited as the proximate cause of the exile (2 Kgs 21:10–15). Yet the line of David passed through him. Christ\'s genealogy traverses the worst of Israel\'s history rather than bypassing it. The Redeemer comes from within the full weight of the human condition he enters to redeem, not from a protected lineage kept free of corruption.</p>',

    "11": '<p>The Babylonian deportation — named twice (here and v12) — is the defining catastrophe of Israel\'s covenantal history. Jechoniah is the last Davidic king before the throne is effectively lost; the curse of Jer 22:30 (no descendant shall prosper sitting on David\'s throne) stands over the line. Matthew\'s careful framing at v16 threads this needle: legal Davidic descent through Joseph (adoptive paternity was legally equivalent in Jewish law) without biological paternity. The legal claim stands; the Jeremiah curse does not transfer biologically to the one born of Mary alone.</p>',

    "12": '<p>Zerubbabel led the first post-exilic return from Babylon (Ezra 2:2) and received messianic-sounding language from Haggai (Hag 2:23, "I will make you like a signet ring"). His presence marks the restoration period — the partial fulfillment that nonetheless carried the hope of a greater Davidic restoration. The genealogy covers every phase: election, kingdom, judgment, exile, restoration, and finally — in Jesus — the fulfillment that all the restorations anticipated but could not themselves achieve.</p>',

    "13": '<p>Post-exilic ancestors — Abiud through Azor — whose names appear in no other biblical source. The genealogy passes through historically obscure people across the Second Temple centuries. The covenant did not require imperial visibility; it was carried in families. The Messiah\'s lineage includes the famous (Abraham, David) and the forgotten. The promise is not contingent on the fame or power of its human bearers; it is God\'s word, and it will arrive at its appointed time.</p>',

    "14": '<p>Zadok through Eliud — further post-exilic names. The quiet maintenance of the Davidic line through the Persian and Hellenistic periods, when there was no Davidic throne and Israel was a subject people, is itself a Christological statement: God\'s promise was not extinguished by political circumstances. The prophets had articulated this confidence (Isa 55:3; Amos 9:11; Ezek 34:23–24); the genealogy embodies it in human names across forgotten generations.</p>',

    "15": '<p>Eleazar through Jacob — the final three generations before Joseph. The genealogy is moving toward its resolution; the reader familiar with Israel\'s story knows that the long series of names is converging on the one who will answer all the covenant promises. Matthew structures the genealogy in three acts of fourteen, as if the rhythm of history itself is calibrated toward this arrival. The three acts are not random groupings but the three phases of the covenant: establishment, testing, and fulfillment.</p>',

    "16": '<p>The genealogy\'s pivot verse. Every previous entry uses the active "was the father of" (<em>egennēsen</em>); here the verb is passive — Jesus "was born" (<em>egennēthē</em>) of Mary. Joseph is "the husband of Mary" rather than "the father of Jesus." The legal Davidic descent is transmitted through Joseph\'s adoption (legally equivalent to paternity in Jewish law); the biological birth is from Mary alone, by divine action. This verse is the hinge that the birth narrative (vv18–25) will explain: the genealogy culminates in a birth unlike all the others, establishing that Jesus is both fully within the covenant line and uniquely originated by God.</p>',

    "17": '<p>Matthew\'s editorial summary draws attention to the three-part structure: Abraham to David (covenant establishment), David to the exile (covenant tested and partially forfeited), exile to Christ (covenant restored beyond what any restoration had achieved). The number fourteen has been read as a gematria of David\'s name (D-W-D = 4+6+4 in Hebrew numeration) — each period is a "David-cycle." Whether intentional or not, the structure declares: Jesus is the third and final David, the one in whom the Davidic covenant reaches its fullness. Israel\'s entire history is Christologically organized from the beginning.</p>',

    "18": '<p>The birth narrative opens with <em>genesis</em> — origin, beginning — the same word that began the genealogy. The Spirit\'s role in the conception is the foundation of the Christological claim: the one born is not merely a human descendant of David but has God himself as the source of his human life. Matthew presents this not as mythology but as the fulfillment of the OT promise that God would act personally and directly to save his people. The divine origin does not dissolve Jesus\'s humanity (born of a human mother, placed in the Davidic line, at a specific historical time); it establishes that his origin is unique in kind.</p>',

    "19": '<p>Joseph\'s righteousness (<em>dikaios</em>) here means covenant-faithfulness: a righteous man does not pass off another man\'s child as his own, making false legal claims. His plan to divorce quietly — rather than expose Mary to public trial and potential death under Deut 22:23–24 — is the Mosaic principle of justice expressing itself as mercy. Joseph is the first human figure in the Gospel to embody the pattern Jesus will later teach: righteous without harshness, faithful without cruelty. He is the fitting guardian of the one who will fulfill all righteousness (3:15).</p>',

    "20": '<p>The angel addresses Joseph as "son of David" — only Matthew uses this address for Joseph, emphasizing that Jesus\'s Davidic title is transmitted through Joseph\'s legal adoption. The dream-revelation continues the OT pattern: the patriarch Joseph received divine guidance through dreams (Gen 37; 40–41); this Joseph now receives the same guidance at the birth of a greater Son. The command "do not be afraid to take Mary as your wife" answers exactly the social shame that would otherwise have made compliance impossible: divine command overrides the honor-shame calculus.</p>',

    "21": '<p>A direct Christological statement embedded in the naming: <em>Iēsous</em> is the Greek form of Joshua/Yeshua (YHWH saves), and the angel makes the etymology explicit — "he will save his people from their sins." The name is not merely biographical; it is a program. Every OT framework of salvation — the exodus from Egypt, deliverance from enemies, return from exile — is now gathered into a single person who will accomplish what no military leader or covenant renewal ever fully achieved: salvation from sin itself, the root cause of all Israel\'s catastrophes. The Christological claim: Jesus\'s work is not political liberation but the definitive salvation that all the earlier deliverances foreshadowed.</p>',

    "22": '<p>Matthew\'s first explicit fulfillment formula: <em>hina plērōthē to rhēthen</em> — "in order that what was spoken through the prophet might be fulfilled." Matthew uses this formula ten times in the Gospel (1:22; 2:5, 15, 17, 23; 4:14; 8:17; 12:17; 13:35; 21:4), always with the same structure: event, then OT text, then interpretation. The formula is itself a Christological argument: the events of Jesus\'s life are not incidental but are the intended destination of OT prophecy. Jesus is the one toward whom the prophetic texts were always aimed.</p>',

    "23": '<p>A direct fulfillment of Isa 7:14: the virgin shall conceive and bear a son, and they shall call his name Immanuel — God with us. Matthew uses the LXX <em>parthenos</em> (virgin); the point is not primarily the virginity but the divine name given to the child. <em>Immanuel</em> — God with us — is the Incarnation in a name. The promise given to Ahaz amid unbelief (Isa 7) was not exhausted by its eighth-century context; Jesus\'s birth is the moment when the name becomes literally true: God is bodily and personally with his people in this child. The Gospel will end with the same promise: "I am with you always, to the end of the age" (28:20) — Immanuel as the Gospel\'s frame.</p>',

    "24": '<p>Joseph\'s immediate obedience is the model of the response Jesus will call for from disciples: hearing and doing (7:24–27). The adoption of Mary as wife is covenant-loyalty expressing itself not in separation but in embrace of what God has done. Joseph\'s righteousness (v19) is not nullified by the irregular situation; it is completed by it. The Christological significance: the Incarnation required human cooperation; Joseph\'s obedience is the human side of what the Spirit accomplished in Mary\'s conception. The kingdom of God arrives through willing human instruments who trust the divine command.</p>',

    "25": '<p>Joseph named him Jesus — the act of legal adoption that makes Jesus his son under Jewish law and thus David\'s legal heir. Matthew\'s theology of the Incarnation is complete by the end of ch.1: fully divine (conceived by the Holy Spirit), fully within the human and covenantal order (born of Mary, legally adopted into the Davidic line), and named as the one whose mission defines his identity — <em>Iēsous</em>, YHWH saves. Every subsequent act of Jesus in the Gospel is the outworking of this name.</p>'
  },

  "2": {
    "1": '<p>Bethlehem in Judea is the city of David (1 Sam 16:1–13; 17:12). The Magi from the east — Gentile astrologers, likely Babylonian or Persian — are the first non-Israelites to seek the king of the Jews. Matthew\'s Christological structure is evident from the chapter\'s opening: Gentiles come to worship while Israel\'s political establishment is troubled. This foreshadows the Gospel\'s movement toward "all nations" (28:19); the Magi anticipate the Gentile pilgrimage to Zion that Isaiah promised (Isa 60:1–6). The Messiah arrives not for one ethnic group exclusively but for the world he came to save.</p>',

    "2": '<p>The star fulfills the oracle of Balaam (Num 24:17: "a star shall come out of Jacob, a scepter shall rise out of Israel"), widely read in Second Temple Judaism as a messianic promise. The Magi recognize what the star signals; Herod and all Jerusalem are troubled (v3). Matthew\'s persistent Christological irony is established here: those outside Israel often perceive what those inside fail to see. The revelation of Christ is not restricted by ethnicity or geography; the star is visible beyond Israel\'s borders, and the Gentiles who see it act while Israel\'s establishment does not.</p>',

    "3": '<p>Herod\'s disturbance — and Jerusalem with him — is the first response of earthly power to the Messiah\'s birth. The pattern will recur: the high priests and Pilate will conspire to kill the one the Magi worship. Herod represents the kingdoms of this world that Christ\'s kingdom will displace (cf. 4:8–10, where Satan offers these kingdoms; Herod embodies what that offer looks like when accepted). Matthew presents the Messiah\'s arrival as a political rupture, not a peaceful accommodation of existing power.</p>',

    "4": '<p>The chief priests and scribes can immediately locate Bethlehem from Mic 5:2 — their scriptural expertise is not in question. But they provide the information to Herod and do not go themselves. Knowledge of the text does not produce faith or action. This will be a persistent feature of Matthew\'s portrayal of the religious leadership: scripture deployed in service of opposition rather than recognition. The Christological point: the one who is the fulfillment of the text comes to those who know the promise and decline it as much as to those who are ignorant of it.</p>',

    "5": '<p>The citation of Mic 5:2 is introduced by the chief priests\' own words, making the religious leadership unwitting witnesses to the prophecy they will later reject. The irony is sharp: those who will seek Jesus\'s death are the ones who guide the Magi to him. The OT text does its work even through hostile intermediaries. Bethlehem, the city of David, is the appointed birthplace because Christ\'s Davidic identity must be geographically as well as genealogically established.</p>',

    "6": '<p>A direct fulfillment of Mic 5:2. Matthew\'s quotation blends Mic 5:2 ("you are by no means least among the rulers of Judah") with 2 Sam 5:2 ("you shall shepherd my people Israel"), merging the messianic birthplace prophecy with the Davidic shepherd-king promise. The combination is deliberate: Christ is not merely the Davidic king by descent but the Davidic shepherd by calling (cf. 9:36; 25:31–46; Ezek 34:23–24). The shepherd who rules by care rather than force is the Christological model Matthew will develop throughout the Gospel.</p>',

    "7": '<p>Herod\'s secret inquiry into the star\'s timing is the beginning of his murderous calculation (v16). He presents himself as a fellow worshiper ("so that I too may go and worship," v8) while planning elimination. This mimics the pattern of the temptation in ch.4: apparent accommodation concealing an attempt to destroy. The Messiah navigates a world in which power presents itself as devotion. Matthew\'s Christological point: Jesus is preserved through the hostility of the powerful because his death must be on the Father\'s terms, not any human adversary\'s.</p>',

    "8": '<p>Herod\'s command to "search carefully for the child" and report back is earthly power attempting to locate and eliminate what it cannot control. The Magi will be divinely redirected (v12); Herod\'s intelligence network is defeated by a dream. The divine protection that runs through the birth narrative operates not by preventing hostility but by navigating around it: God guides events through those who are receptive while frustrating the calculations of those who are not.</p>',

    "9": '<p>The star\'s reappearance and movement before the Magi — stopping over the place where the child was — has no natural astronomical parallel. Matthew presents it as miraculous divine guidance comparable to the pillar of cloud and fire that led Israel through the wilderness (Exod 13:21–22). The Magi\'s journey thus recapitulates the Exodus pattern: a guiding light leading a pilgrim people to the dwelling of the one they seek. The theme is revelation of God: the same God who led Israel through the wilderness now leads Gentiles to his Son.</p>',

    "10": '<p>Their overflowing joy at the star\'s reappearance is the fitting response of those who actually desire what God is doing. Matthew will return to this vocabulary: those who find the kingdom rejoice with great joy (13:44); the disciples rejoice when they see the risen Christ (28:8–9). The Magi anticipate the response of all who will believe: seeking, following, and rejoicing at what God reveals. Joy in Matthew is always the register of encountering the kingdom — the sign that what is found is what the heart was made for.</p>',

    "11": '<p>Three convergent acts: they see the child with his mother Mary, they bow and worship (<em>prosekynesan</em> — the same word used for worship of God in Matthew), and they offer gifts that early interpreters read as royal (gold), priestly (frankincense), and mortal-preparatory (myrrh). The Magi\'s worship is the first Gentile recognition of Christ\'s royal and divine identity. Isa 60:6 (nations bringing gold and frankincense to the LORD\'s temple) is the background: the Gentile pilgrimage to Zion is fulfilled not in Jerusalem but in the house in Bethlehem where the Son of God lies.</p>',

    "12": '<p>The divine warning redirecting the Magi continues the pattern of divine guidance through dreams that governs the birth narrative (Joseph: vv20, 22; 2:13, 19; the Magi: v12). This connects Matthew\'s birth narrative to the Genesis Joseph narratives (Gen 37; 40–41): divine guidance navigates around hostile human schemes. Both Christ and his family are preserved not by escape from the hostile world but by divine direction within it. The Messiah arrives in a world whose powers oppose him and is sustained by the Father who sent him.</p>',

    "13": '<p>The flight to Egypt: Jesus recapitulates the Exodus pattern in reverse — the one who will become the new Moses first descends into Egypt as an infant refugee. The angel\'s instruction echoes divine commands throughout Israel\'s history (Gen 12:1, Exod 3:10, Exod 12:31): "get up and go." The urgency ("Herod is about to search for the child to destroy him") places this flight in the pattern of the righteous one preserved from destruction — Moses in the basket (Exod 2:2–3), Israel escaping Egypt, the servant preserved to accomplish his mission.</p>',

    "14": '<p>Joseph\'s immediate, nocturnal obedience echoes the Exodus departure: Israel left Egypt "in haste" at night (Exod 12:31–33; Deut 16:3). The night-flight motif connects Jesus\'s preservation to Israel\'s deliverance. Matthew is constructing a typological argument: the Son called out of Egypt is the true Israel, the one in whom the national story of rescue is personally and fully embodied. His preservation is not merely individual good fortune but the divine protection of the one who carries Israel\'s destiny.</p>',

    "15": '<p>A typological fulfillment: Hos 11:1 ("Out of Egypt I called my son") refers in its original context to the Exodus — Israel as God\'s corporate son called out of Egypt. Matthew applies it to Jesus as the individual Son who recapitulates Israel\'s history. This is typological interpretation: Israel\'s pattern is fulfilled by the one who is Israel\'s head and representative. The Exodus was always pointing forward to a definitive rescue — not from Egypt but from sin and death — that the Son alone could accomplish. Christ coming out of Egypt is Israel\'s foundational story arriving at its personal, flesh-and-blood fulfillment.</p>',

    "16": '<p>Herod\'s massacre of the Bethlehem infants parallels Pharaoh\'s slaughter of Hebrew infants (Exod 1:16–22) — the Messiah\'s birth provokes the same attempt at suppression that Moses\'s birth provoked. Innocent children die because of their proximity to the Messiah; the world\'s hostility toward the Son overflows onto those around him. The Christological weight: opposition to Christ has real human cost; the powers that resist him will not limit their violence to the one they seek. This is not a theodicy problem Matthew leaves unanswered — it is answered by vv17–18 and ultimately by the resurrection.</p>',

    "17": '<p>Matthew\'s formula "then was fulfilled" (<em>tote eplērōthē</em>) — slightly less deliberate than the earlier "in order that it might be fulfilled" — signals a pattern-fulfillment rather than a predictive one. Rachel weeping (Jer 31:15) was originally about the Babylonian exile — mothers weeping at Ramah as children were deported. Matthew sees the same pattern of lamentation over children lost to historical violence in the Bethlehem massacre. The Christological point: the Messiah\'s coming is not without suffering; he enters a world already carrying the grief of the powerful crushing the innocent.</p>',

    "18": '<p>The Jeremiah context of Jer 31:15 is crucial: it immediately precedes the promise of the new covenant (Jer 31:31–34). Rachel\'s weeping is not Jeremiah\'s final word; restoration, return from exile, and the new covenant follow. Matthew\'s use of the lament passage thus implies the whole context: the mourning surrounding Christ\'s birth anticipates the new covenant he will establish (26:28). The grief is real; the hope it announces is greater than the grief. The pattern of death-before-resurrection is embedded in the birth narrative itself.</p>',

    "19": '<p>Herod\'s death removes the immediate threat. The angel\'s message to Joseph mirrors the divine word to Moses: "those who were seeking your life are dead" (Exod 4:19). Matthew explicitly parallels Jesus\'s situation with Moses\'s — the infant preserved while others died, the persecutor dying before the child\'s mission can be thwarted, the return from the threatening land. Jesus is the new Moses, not merely analogically but as the one who will deliver a definitive exodus from the bondage that the Mosaic exodus foreshadowed.</p>',

    "20": '<p>The command "go to the land of Israel" echoes the divine direction to every significant figure in Israel\'s story who sojourned outside the land: Abraham (Gen 12:1), Jacob (Gen 31:3), Moses (Exod 4:19). Jesus returns to the land not as a refugee returning to normalcy but as the Son entering his inheritance. "The land of Israel" is the covenantal gift; Jesus coming into it is the arrival of the one to whom the land ultimately belongs as its Davidic king.</p>',

    "21": '<p>The return from Egypt completes the typological arc: as Israel came out of Egypt under Moses, the Son comes out of Egypt to begin his mission. Jesus has been born into the Davidic line (ch.1), threatened by the powers of this world, preserved by divine guidance, and now enters the land to fulfill all that Israel\'s story anticipated. The geography of the birth narrative is not incidental travel but the deliberate recapitulation of Israel\'s defining journey: out of exile, into the land, toward the mission.</p>',

    "22": '<p>Joseph\'s second dream — redirecting the family to Galilee rather than Judea — keeps Jesus away from Jerusalem until his appointed time (21:1). The narrative geography of Matthew\'s Gospel is Christologically shaped: Jesus begins and conducts most of his ministry in Galilee (the region of Zebulun and Naphtali, Isa 9:1–2, fulfilled at 4:12–16), among those considered least in Jewish estimation, before his climactic journey to Jerusalem. The geography is fulfillment-shaped: the messianic light breaks where Isaiah said it would — in the shadow lands, on the periphery.</p>',

    "23": '<p>The most difficult of Matthew\'s fulfillment quotations — no single OT verse says "he shall be called a Nazarene." Most interpreters read this as drawing on multiple prophetic threads: the <em>netzer</em> (branch/shoot) of Isa 11:1 (a shoot from the stump of Jesse), the Nazirite consecration (Num 6; cf. Judg 13:5, 7 — Samson the judge-deliverer consecrated from birth), and the "despised" register of Isa 53:3 (Nazareth was regarded as insignificant, John 1:46). Matthew\'s claim: Jesus\'s Galilean origins in Nazareth fulfill the prophetic pattern of the Messiah\'s obscurity and rejection before exaltation — the shoot from Jesse\'s cut-down stump that no one expected.</p>'
  },

  "3": {
    "1": '<p>John the Baptist in the Desert of Judea inaugurates the final act of OT expectation. The desert setting is theologically loaded: it is where the Mosaic covenant was given, where Elijah was recommissioned (1 Kgs 19), and where Isa 40:3 located the preparation for the LORD\'s coming. John\'s desert ministry is the signal that the long exile — not merely the Babylonian deportation but the spiritual condition of Israel awaiting the fulfillment of the covenant promises — is about to end. The Messiah\'s forerunner arrives first, as the OT pattern required (Mal 3:1; 4:5).</p>',

    "2": '<p>The proclamation "Repent, for the kingdom of heaven has come near" is the announcement that the whole OT longing is arriving. "Kingdom of heaven" (<em>basileia tōn ouranōn</em>) is the rule of God breaking into history in the person and work of Jesus. The call to repentance is not a moral reform program but a reorientation of the whole self toward the covenant: Israel must decide whether it will receive the kingdom\'s king. John\'s preaching frames Jesus\'s arrival as a decision-moment, not merely a miraculous event to observe at a distance.</p>',

    "3": '<p>A direct fulfillment: Isa 40:3 (the voice in the wilderness preparing the LORD\'s way) applied to John. Isaiah 40 opens the "Book of Comfort," the announcement that Israel\'s exile is over and the LORD himself is returning to Zion. Matthew identifies this text as fulfilled in John — which means the LORD who is coming is Jesus. The Christological claim is staggering: the one who in Isa 40 is YHWH returning to his people is the one John is announcing. Jesus\'s identity with YHWH is implied in the fulfillment quotation before Jesus speaks or acts a single time in the Gospel.</p>',

    "4": '<p>John\'s clothing and diet evoke Elijah: the same camel-hair garment and leather belt are described in 2 Kgs 1:8 as Elijah\'s identifying marks. Matthew will make the identification explicit (11:14; 17:10–13), but the visual cues are here for readers with OT eyes. The Christological function: Elijah\'s return was the OT sign that the Day of the LORD was imminent (Mal 4:5–6). John\'s Elijah-dress announces that the last prophet before the end has arrived; the greater one who follows (v11) is the one the Elijah-sign was pointing toward.</p>',

    "5": '<p>The mass response — Jerusalem, all Judea, and the whole region of the Jordan going out to John — demonstrates the depth of messianic expectation in first-century Israel. The people recognized in John\'s preaching the language of the prophets. They came to be baptized in the Jordan as Israel had once crossed the Jordan into the Promised Land. Matthew\'s point: the Messiah arrives into a people prepared by expectation, a people whose response to the forerunner anticipates their response (for good and ill) to the Messiah himself.</p>',

    "6": '<p>Baptism in the Jordan for the forgiveness of sins treats Israel as if needing to re-enter the covenant from outside — a radical act. The Christological implication: the one John announces will accomplish the definitive forgiveness that John\'s baptism signifies but cannot provide. John baptizes with water (v11); Jesus will baptize with the Holy Spirit and fire. The repentance-and-forgiveness structure of John\'s ministry is the preparation for the actual forgiveness that only the Lamb of God can offer (John 1:29; Matt 26:28).</p>',

    "7": '<p>John\'s challenge to the Pharisees and Sadducees — "who warned you to flee from the coming wrath?" — establishes that the Messiah\'s arrival is also an arrival of judgment. The "coming wrath" draws on OT Day of the LORD imagery (Isa 13:9–11; Joel 2:1–2; Zeph 1:14–18; Mal 4:1). John\'s preaching positions Jesus\'s coming as simultaneously salvation and judgment: the same event is rescue for those who repent and reckoning for those who do not. The Messiah does not arrive to endorse existing religious standing but to evaluate it.</p>',

    "8": '<p>Fruit worthy of repentance (<em>karpos axios tēs metanoias</em>) is the criterion John sets for genuine covenant-renewal. Matthew will develop this fruit-test throughout the Gospel: 7:16–20 (you will know them by their fruits), 12:33, 21:43. Jesus himself will embody the criterion he requires — his life is the perfect fruit of covenant faithfulness — and he will be recognized by those who produce fruit like his. The Christological coherence: the standard John announces is the standard the coming one perfectly meets.</p>',

    "9": '<p>The challenge to Abrahamic presumption — "God can raise up children of Abraham from these stones" — dismantles ethnic-covenantal security. Abraham-sonship is a gift of divine creative power, not biological descent. This prepares for the reconfiguration of the covenant people around Jesus: those who do the will of the Father are his family (12:50); the Gentiles who produce fruit will receive the kingdom the natural heirs forfeited (21:43). The Messiah\'s arrival does not endorse an existing ethnic privilege but creates a new community defined by response to him.</p>',

    "10": '<p>The axe at the root of the trees (<em>axinē pros tēn rhizan keitai</em>) is imminent judgment: not pruning (which allows regrowth) but uprooting. The urgency of John\'s preaching is the urgency of the Messiah\'s arrival — the window for response is open but it will close. Matthew\'s Christology includes the coming judgment as part of what the Messiah brings; the kingdom\'s arrival is not gentle accommodation but decisive sorting. The theme of judgment-through-the-tree runs through Matthew (7:19; 13:40; 21:18–19) as the counterpart to the theme of gathered harvest.</p>',

    "11": '<p>John\'s self-subordination — "he is more powerful than I, and I am not worthy to carry his sandals" — is the clearest signal of Christological magnitude in the birth and preparation narratives. The one coming will baptize with the Holy Spirit and fire: a dual metaphor drawing on the Spirit\'s purifying work (Ezek 36:25–27; Joel 2:28–29) and the refining fire of judgment (Mal 3:2–3; Isa 4:4). The Pentecost Spirit-baptism (Acts 2) and the eschatological judgment are both present in John\'s proclamation. Christ brings both the salvation and the reckoning that Israel\'s prophets had announced as the Day of the LORD.</p>',

    "12": '<p>The winnowing-fork separating wheat from chaff draws from Isa 41:15–16 and Jer 15:7. Christ is the agent of the final division: gathering the wheat into the barn (the Father\'s house) and burning the chaff with unquenchable fire. Matthew will develop this eschatological-judgment theme in the parables (wheat and tares, 13:24–30; dragnet, 13:47–50; ten virgins, 25:1–13; sheep and goats, 25:31–46). John announces both the salvation and the judgment that Christ\'s single coming achieves; they are not separated events but the two sides of the same arrival.</p>',

    "13": '<p>Jesus comes from Galilee to the Jordan to be baptized by John — a voluntary act of solidarity with the people John is calling to repentance. The Sinless One submits to a baptism of repentance not because he needs it but because he is identifying himself with the people he comes to save. This is the first act of the "fulfilling all righteousness" he will explain in v15: covenant-faithfulness expressed as identification with sinful humanity rather than separation from it. The Christological movement is downward: the Son of God enters the waters where sinners go.</p>',

    "14": '<p>John\'s attempt to prevent the baptism — "I need to be baptized by you, and do you come to me?" — is the clearest recognition by any human figure in the preparation narratives of Jesus\'s unique status. John perceives the incongruity: the one who baptizes with the Spirit does not need water baptism. The greater should not be subject to the lesser. The reversal Jesus insists on ("let it be so now") is the paradigm of the Incarnation itself: the one who is greater stoops to the position of the lesser in order to fulfill the covenantal purpose. He does not come to be served but to serve (20:28).</p>',

    "15": '<p>Jesus\'s explanation — "it is proper for us to fulfill all righteousness" — is a key Christological statement. <em>Dikaiosynē</em> in Matthew\'s usage means covenant-faithfulness, the doing of what God requires. Jesus\'s baptism is the first public act of a life of complete covenant-obedience that will culminate in the cross: he submits to every requirement of the covenant not because he has broken it but because his people have, and he bears the fullness of their obligation as their representative. The baptism inaugurates the public ministry of the one who will live the life Israel was called to live and bear the judgment Israel incurred for failing.</p>',

    "16": '<p>Three Christological events converge at the baptism: the Spirit descends like a dove (the anointing of the Messiah; Isa 61:1 "the Spirit of the LORD is upon me ... he has anointed me"), the heavens open (the apocalyptic sign of divine accessibility; cf. Ezek 1:1), and the Father speaks. The dove recalls the dove of Noah\'s flood (Gen 8:11), the sign that the judgment-waters had receded and a new era begun. Jesus\'s baptism is a new-creation moment: the Spirit hovering over the waters (Gen 1:2), the new humanity emerging from the flood-waters of judgment, the new covenant beginning with the Spirit\'s anointing.</p>',

    "17": '<p>The Father\'s declaration — "This is my Son, whom I love; with him I am well pleased" — synthesizes two OT texts. "My Son" echoes Ps 2:7 (the royal enthronement psalm: "You are my Son; today I have begotten you"), identifying Jesus as the Davidic king in the fullest sense — the one to whom all nations are given as an inheritance. "Whom I love" and "well pleased" echo Isa 42:1 (the first Servant Song: "my chosen, in whom my soul delights; I have put my Spirit upon him"). Both strands — royal Messiah (Ps 2) and Suffering Servant (Isa 42) — are combined in a single declaration. Matthew\'s Christology is not merely royal or merely suffering-servant; it is both, and the baptism names both together at the outset of the public ministry.</p>'
  },

  "4": {
    "1": '<p>Immediately after the Father\'s declaration — "This is my Son" — the Spirit leads that Son into the wilderness to be tested. The structure is deliberate: the identity established at baptism (Son of God, Davidic king, Servant) is immediately pressed by the adversary. The wilderness setting continues the Exodus typology: as Israel was led into the wilderness after the Red Sea crossing, Jesus is led into the desert after the Jordan baptism. As Israel spent forty years in the wilderness, Jesus spends forty days. The test is: will the Son of God be what Israel was called to be but failed to be?</p>',

    "2": '<p>Forty days and forty nights of fasting connects Jesus to the two great wilderness fasters: Moses (Exod 34:28, before receiving the Torah on Sinai) and Elijah (1 Kgs 19:8, on his journey to Horeb). The Christological framing: Jesus stands in the tradition of the law-giver and the prophets, but as their fulfillment rather than their peer (cf. the Transfiguration, 17:3, where Moses and Elijah appear with him). The hunger at the end of the fast is genuine human weakness; the temptations exploit this weakness exactly as all human temptation works — at the point of real need.</p>',

    "3": '<p>The tempter\'s first challenge — "if you are the Son of God, tell these stones to become bread" — attacks the Father\'s declaration at baptism. The "if" (<em>ei</em>, conditional: "since you are the Son of God") is not doubt about Jesus\'s identity but an invitation to use that identity for self-provision rather than filial trust. Israel grumbled for bread in the wilderness (Exod 16:1–3); the lesson of the manna was supposed to be trust in God\'s provision, not the bread itself. The temptation is to establish messianic identity through self-sufficiency rather than dependence on the Father.</p>',

    "4": '<p>Jesus cites Deut 8:3 — Moses\'s retrospective meditation on the manna: "he humbled you and let you hunger and fed you with manna ... that he might make you know that man does not live by bread alone, but by every word that comes from the mouth of God." Jesus meets the temptation not with a miracle but with the scripture Israel had been given to internalize the wilderness lesson. Where Israel failed (grumbling instead of trusting), Jesus succeeds by living out the Torah\'s own teaching. This is the first demonstration that he fulfills all righteousness (3:15) by embodying what Israel was called to embody.</p>',

    "5": '<p>The holy city and the pinnacle of the temple — the center of Israel\'s worship and the dwelling of God\'s presence. Satan transports Jesus to the place where messianic demonstrations were expected by some Second Temple traditions (Messianic appearances at the temple roof appear in later Jewish texts). The temptation moves from personal provision (bread) to public spectacle: use the Father\'s protection for a dramatic demonstration that would compel recognition. The Christological pressure is toward a messiahship established through signs that force belief rather than invite it.</p>',

    "6": '<p>Satan quotes Ps 91:11–12 against Jesus — a sophisticated temptation that weaponizes scripture. The Ps 91 protection is real (angels do minister to Jesus after the temptation, v11; he is preserved through repeated hostility until his appointed hour). But the protection is for the Son who trusts, not the Son who tests. The Christological distinction: the Father\'s protection is not a performance guarantee that can be invoked on demand; it is the context within which obedience unfolds. Using it as a proof-text would convert covenant-trust into divine testing — the very thing the next verse forbids.</p>',

    "7": '<p>Jesus counters with Deut 6:16 — "Do not put the Lord your God to the test" — which refers specifically to Israel\'s demand for proof at Massah (Exod 17:1–7: "Is the LORD among us or not?"). The second great wilderness failure was demanding demonstration of God\'s presence and power. Jesus refuses to replicate it. The Christological pattern is consistent: every temptation mirrors an Israel-failure; every response demonstrates covenant-faithfulness by quoting the Torah that Israel was given to learn from those failures. The new Israel succeeds precisely where the old one failed.</p>',

    "8": '<p>The third temptation moves to the summit of all human ambition: all the kingdoms of the world and their splendor. This is what the messianic kingdom will ultimately encompass (Ps 2:8, "I will make the nations your inheritance, the ends of the earth your possession"; Dan 7:13–14, the Son of Man receiving dominion over all peoples). Satan offers the destination without the cross — the glory without the suffering, the inheritance without the death that purchases it. The temptation is to receive the Davidic-messianic inheritance by a shortcut that bypasses the redemptive purpose of the Incarnation.</p>',

    "9": '<p>The demand for worship (<em>prosekynesan moi</em>) is the naked Christological claim at stake in the temptation sequence. Jesus has been declared God\'s Son (3:17); the devil now inverts this by demanding that the Son treat him as god. The kingdoms are real (Satan is "the ruler of this world," John 12:31; 14:30); the offer is not empty. But their ultimate ownership is Christ\'s by right of inheritance and by the cross. To receive them from Satan would be to receive them outside the Father\'s covenant order — a messiahship without redemption, a throne without the kingdom worth having.</p>',

    "10": '<p>The rebuke — "away from me, Satan!" — and the third Deuteronomy quotation (Deut 6:13: "Worship the Lord your God and serve only him") closes the temptation sequence. Jesus quotes from the Shema-context: Deut 6:4–15 is the call to exclusive covenant-loyalty that Israel violated at the golden calf (Exod 32) and throughout the monarchy. Jesus\'s third success is Israel\'s third wilderness failure undone: no idolatry, no divided worship. The Messiah proves his identity as Israel-fulfilled by refusing what the old Israel repeatedly chose. He is the covenant-keeper who makes atonement possible for covenant-breakers.</p>',

    "11": '<p>The angels ministering to Jesus after the temptation is the vindication-after-testing pattern: as Elijah was fed by an angel after his wilderness exhaustion (1 Kgs 19:5–7), as Ps 91:11 promised angelic care, Jesus receives the Father\'s provision after his ordeal. The protection that the temptation sought to weaponize now appears naturally, in its proper mode: not a demonstration compelled by Jesus but the Father\'s gift to the Son who trusted. The Christological principle: obedience receives what presumption demands and does not receive.</p>',

    "12": '<p>John\'s imprisonment is the signal that the forerunner\'s work is done; the one he announced steps into his place. The withdrawal to Galilee is not retreat but fulfillment-geography: Galilee of the Gentiles (Isa 9:1–2) is where the messianic light is to shine first. Matthew traces a movement away from Jerusalem toward the periphery — the margins, the Gentile borderlands, the people considered least in Israel\'s religious establishment. This geographic pattern is itself Christological: the kingdom arrives at the edges first, among the unexpected recipients, before its climax in Jerusalem.</p>',

    "13": '<p>Capernaum on the Sea of Galilee, in the region of Zebulun and Naphtali — Matthew identifies the location precisely because it is the fulfillment-location. The Isaiah prophecy (vv15–16) names these specific territories. Capernaum becomes Jesus\'s base of operations (9:1 calls it "his own city") — the headquarters of the Galilean ministry that Isaiah had predicted would be illuminated. The Messiah makes his dwelling among the people "living in darkness," those considered least in Israel\'s religious landscape.</p>',

    "14": '<p>Matthew\'s fulfillment formula — "to fulfill what was said through the prophet Isaiah" — applies to the location of Jesus\'s ministry headquarters. The move to Capernaum is not strategic geography but prophetic fulfillment. This is the same interpretive principle Matthew has applied throughout chs.1–4: the apparently contingent events of Jesus\'s life — escape route, hometown, ministry base — are the unfolding of the prophetic script. Matthew\'s Christology requires the reader to see Jesus\'s biography as the OT canon\'s destination.</p>',

    "15": '<p>Isa 9:1–2 in full: the territories of Zebulun and Naphtali were the first to fall to the Assyrian invasion (2 Kgs 15:29), the first into darkness. They therefore receive the messianic light first — a pattern of last-to-first, margin-to-center that Matthew will develop throughout the Gospel (5:3–12; 19:30; 20:16; 21:28–32). "Galilee of the Gentiles" signals the mixed ethnic character of the region and anticipates the ultimate scope of the mission: the light that breaks first in Galilee of the Gentiles will reach all nations (28:19). Geography is prophecy in Matthew\'s Gospel.</p>',

    "16": '<p>A direct fulfillment: "the people living in darkness have seen a great light; on those living in the land of the shadow of death a light has dawned." The people are Israel in the northern territories; the application is universal — all humanity lives in the darkness of sin and death that only Christ can dispel. Jesus is the great light (John 1:4–9; 8:12; 12:46). Matthew uses Isa 9:2 as the Christological signature of the Galilean ministry: Jesus is not primarily a moral reformer or a healer (though he is both) but the Light the prophetic tradition announced — the dawn of the new age, breaking where and on whom no one expected.</p>',

    "17": '<p>Jesus begins preaching with the same words as John (3:2): "Repent, for the kingdom of heaven has come near." The verbal repetition signals continuity — Jesus fulfills what John prepared — but the Christological difference is decisive: when John said "the kingdom is near," he meant it was approaching through the one coming after him; when Jesus says it, he is the kingdom\'s presence. The kingdom has come near because the King is here. The eschatological future that the prophets announced is not merely approaching; it is arriving in the person and work of Jesus.</p>',

    "18": '<p>The calling of Simon and Andrew is a Christological act: Jesus exercises the authority of the Servant-King by summoning followers who immediately abandon their livelihood. No teacher in first-century Judaism summoned disciples; disciples chose their teachers. Jesus\'s reversal of this pattern is a claim of unique authority. He calls, and the fitting response is immediate and total. The fishing context is instantly reframed — the vocation of these brothers is redirected into the eschatological mission ("fish for people") that the whole Gospel will unfold.</p>',

    "19": '<p>"Come, follow me, and I will send you out to fish for people" — the call is simultaneously invitation and commission. "I will send you out" (<em>poiēsō hymas halieis anthrōpōn</em>) carries Jer 16:16 in the background (where God promises to send "fishers" to gather the scattered Israelites) and Ezek 47:9–10 (the eschatological river from the temple). Jesus\'s summons is the beginning of the eschatological gathering the prophets had announced — not the harvest of individual conversions but the ingathering of the people of God from the four winds.</p>',

    "20": '<p>The immediate response — "at once they left their nets and followed him" — is presented without psychological motivation or negotiation. Matthew\'s emphasis is on the authority of the call and the adequacy of the response. This is how the kingdom operates: those who hear the Messiah\'s call respond wholly or not at all. The leaving of nets represents the transfer of ultimate allegiance — from one master to another, from one vocation to its fulfillment. The Messiah forms his community by calling, and the community is defined by its response to that call.</p>',

    "21": '<p>James and John are called in the same manner. Their situation adds a dimension: they are called from their father, not only from their livelihood. The cost of discipleship includes the family bonds that antiquity treated as primary obligations. Matthew will later record Jesus\'s word that he came to set a man against his father (10:35–37) and that those who love father or mother more than Jesus are not worthy of him. The calling of the disciples is itself a Christological statement: the authority of the Son over human life exceeds the authority of every prior claim, including family.</p>',

    "22": '<p>The identical pattern — "immediately they left the boat and their father and followed him" — establishes the structure of the disciple-community: called away from all prior claims, gathered around Jesus. The twelve disciples named at 10:1–4 form the new Israel reconstituted around its Messiah — the new twelve tribes gathered around the new Moses who will give the covenant teaching on the mountain (5:1). The calling of the first four disciples at the Sea of Galilee is the embryonic form of what the whole Gospel narratives: the gathering of a renewed people defined by their response to Jesus.</p>',

    "23": '<p>Matthew\'s programmatic summary of the Galilean ministry — teaching in the synagogues, preaching the good news of the kingdom, healing every disease and sickness — is the three-fold fulfillment of the Isaianic Servant\'s anointed mission. Isa 61:1–2 has exactly this structure: anointed to preach good news, heal the brokenhearted, proclaim the year of the LORD\'s favor. Matthew does not cite the passage here but describes its fulfillment. Each element corresponds: the synagogue teaching is covenant-instruction, the kingdom proclamation is the eschatological announcement, and the healings are the signs that the kingdom has arrived in him.</p>',

    "24": '<p>The comprehensive healings — every disease and sickness, demoniacs, epileptics, paralytics — are the reversal of the curse. Genesis 3 introduced suffering, disease, and death as the consequences of the broken covenant; the Messiah\'s arrival begins undoing these consequences in individual bodies. Each healing is a sign of the kingdom: not yet the final restoration (which awaits the resurrection), but the foretaste and guarantee of it. The healing ministry is eschatological in character — it demonstrates in present bodies what the whole creation will experience when the Son of Man comes in his glory (25:31–46).</p>',

    "25": '<p>The crowds from Galilee, the Decapolis, Jerusalem, Judea, and the region across the Jordan — the full geographic range of the Jewish world and Gentile borderlands — gather around Jesus before the Sermon on the Mount. Matthew\'s framing is Christological: the one about to deliver the new-covenant teaching (chs.5–7) draws his audience from the same geography Isaiah described as receiving the messianic light (4:15–16). The crowd who hears the Sermon is the eschatological assembly — Israel and the nations standing before the one who teaches with authority greater than Moses (7:28–29).</p>'
  }
}


def main():
    existing = load_comm('mkt-christ', 'matthew')
    merge_comm(existing, MATTHEW)
    save_comm('mkt-christ', 'matthew', existing)
    ch14 = sum(len(existing.get(ch, {})) for ch in ['1','2','3','4'])
    print(f'Matthew 1–4 mkt-christ written ({ch14} verses in chs 1–4).')

if __name__ == '__main__':
    main()
